@app.post("/predict")
def predict(request: PredictRequest):
    features = (
        request.sepal_length,
        request.sepal_width,
        request.petal_length,
        request.petal_width,
    )
    if features in CACHE:
        prediction = CACHE[features]
        cached = True
    else:
        predicted_class = model.predict([list(features)])[0]
        prediction = target_names[int(predicted_class)]
        CACHE[features] = prediction
        cached = False

    record = {**request.model_dump(), "prediction": prediction, "cached": cached}
    PREDICTION_LOG.append(record)
    return record

def test_health_endpoint():
    response = client.get("/health")
    assert response.status_code == 200
    assert response.json() == {"status": "ok"}


def test_predict_endpoint_returns_real_iris_prediction_and_cached_flag():
    response = client.post(
        "/predict",
        json={"sepal_length": 5.1, "sepal_width": 3.5, "petal_length": 1.4, "petal_width": 0.2},
    )
    assert response.status_code == 200
    body = response.json()
    assert body["prediction"] in {"setosa", "versicolor", "virginica"}
    assert body["cached"] is False


